cat /app/app/auth/compare.go > /tmp/compare.go.bak && echo 'package auth

import (
	"crypto/subtle"
)

// compareHashes compares two hex-encoded hash strings for equality in constant time.
func compareHashes(stored, input string) bool {
	if len(stored) != len(input) {
		return false
	}
	return subtle.ConstantTimeCompare([]byte(stored), []byte(input)) == 1
}' > /app/app/auth/compare.go
